mapper.update:
UPDATE wj_staff
SET category    = #{category},
    category_ord = #{category_ord,jdbcType=INTEGER},
    name         = #{name},
    job          = #{job,jdbcType=VARCHAR},
    phone        = #{phone,jdbcType=VARCHAR},
    email        = #{email,jdbcType=VARCHAR},
    sort_order   = #{sort_order,jdbcType=INTEGER}
    , photo_url = #{photo_url}
WHERE idx = #{idx}

UPDATE wj_department
SET worship_time  = #{worship_time,jdbcType=VARCHAR},
    worship_place = #{worship_place,jdbcType=VARCHAR}
WHERE dept_key = #{dept_key}

UPDATE wj_department_staff
SET role = #{role,jdbcType=VARCHAR}, name = #{name}, sort_order = #{sort_order,jdbcType=INTEGER}
WHERE idx = #{idx}

UPDATE wj_department_teacher
SET label = #{label,jdbcType=VARCHAR}, name = #{name}, sort_order = #{sort_order,jdbcType=INTEGER}
WHERE idx = #{idx}

UPDATE wj_department_section
SET title = #{title}, content = #{content,jdbcType=LONGVARCHAR}
WHERE idx = #{idx}
